      <li><b>\u5171\u901A\u8A2D\u5B9A</b>\uFF1AQualys \u63A5\u7D9A\u5148 POD\u3001\u30D7\u30ED\u30AD\u30B7 URL\u3001\u4FDD\u5B58\u671F\u9593\uFF08\u65E5\uFF09\u3001\u30E9\u30A4\u30BB\u30F3\u30B9\u4E0A\u9650\u3002</li>
