      <li>\u5DE6\u306E\u30AB\u30EC\u30F3\u30C0\u30FC\u3067\u5909\u66F4\u65E5\u3092\u78BA\u8A8D\uFF08\u30AF\u30EA\u30C3\u30AF\u3067\u5F53\u65E5\u3001\u30C9\u30E9\u30C3\u30B0\uFF0FShift\uFF0B\u30AF\u30EA\u30C3\u30AF\u3067\u7BC4\u56F2\uFF09\u3002\u671F\u9593\u30FB\u7A2E\u5225\u3067\u3082\u7D5E\u308A\u8FBC\u307F\u3002</li>
